'use client';
import React, { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useSelector } from 'react-redux';
import { 
  FiHexagon, FiLayers, FiCheckCircle, FiUsers, FiBriefcase, 
  FiActivity, FiArrowLeft, FiX, FiCheck, FiInfo, FiClock, FiCalendar, FiImage
} from 'react-icons/fi';
import adminService from '../../../services/adminService';
import Link from 'next/link';

export default function AdminApprovalsPage() {
  const router = useRouter();
  const { isAuthenticated, user } = useSelector((state) => state.auth);

  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedBiz, setSelectedBiz] = useState(null);
  const [isProcessing, setIsProcessing] = useState(false);

  useEffect(() => {
    if (!isAuthenticated || user?.role !== 'admin') {
      router.push('/login');
    } else {
      fetchPending();
    }
  }, [isAuthenticated, user]);

  const fetchPending = async () => {
    setLoading(true);
    try {
      const res = await adminService.getPendingBusinesses().catch(() => ({ data: [
        { id: 1, name: 'Patil Electricals', owner_name: 'Suresh Patil', category_name: 'Electrical', image: 'https://images.unsplash.com/photo-1621905251918-48416bd8575a?q=80&w=400', createdAt: new Date().toISOString() },
        { id: 2, name: 'Quick Fix Plumbing', owner_name: 'Mahesh Kumar', category_name: 'Plumbing', image: 'https://images.unsplash.com/photo-1504328345606-18bbc8c9d7d1?q=80&w=400', createdAt: new Date().toISOString() }
      ] }));
      setData(res.data || res);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const handleAction = async (id, type) => {
    setIsProcessing(true);
    try {
      if (type === 'approve') {
        await adminService.verifyBusiness(id);
      }
      setData(prev => prev.filter(item => item.id !== id));
      setSelectedBiz(null);
      alert(`Business ${type === 'approve' ? 'Approved' : 'Rejected'} Successfully`);
    } catch (e) {
      alert('Action failed');
    } finally {
      setIsProcessing(false);
    }
  };

  if (loading) return <div style={{ padding: '100px', textAlign: 'center', backgroundColor: '#0F172A', color: '#FFF', minHeight: '100vh' }}>⏳ Accessing verification queues...</div>;

  return (
    <div style={{ backgroundColor: '#0F172A', minHeight: '100vh', color: '#F8FAFC' }}>

      <div style={{ display: 'flex' }}>
        {/* Sidebar Parity */}
        <aside style={{ 
          width: '280px', height: '100vh', position: 'sticky', top: 0, 
          backgroundColor: '#1E293B', borderRight: '1px solid rgba(255,255,255,0.05)',
          padding: '40px 24px', display: 'flex', flexDirection: 'column'
        }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '60px' }}>
             <div style={{ backgroundColor: 'var(--color-primary)', padding: '10px', borderRadius: '12px' }}>
                <FiHexagon size={24} color="#FFF" />
             </div>
             <span style={{ fontSize: '22px', fontWeight: '900', letterSpacing: '-1px' }}>
               Admin<span style={{ color: 'var(--color-primary)' }}>Hub</span>
             </span>
          </div>

          <nav style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '8px' }}>
             {[
               { icon: <FiLayers />, label: 'Dashboard', route: '/admin/dashboard' },
               { icon: <FiCheckCircle />, label: 'Approvals', active: true, badge: data.length, route: '/admin/approvals' },
               { icon: <FiUsers />, label: 'User Directory', route: '#' },
               { icon: <FiBriefcase />, label: 'Businesses', route: '#' },
               { icon: <FiActivity />, label: 'System Logs', route: '#' },
             ].map(item => (
                <Link key={item.label} href={item.route} style={{ textDecoration: 'none' }}>
                  <div style={{ 
                    padding: '14px 16px', borderRadius: '12px', display: 'flex', alignItems: 'center', gap: '12px', 
                    backgroundColor: item.active ? 'rgba(30,64,175,0.1)' : 'transparent',
                    color: item.active ? 'var(--color-primary)' : '#94A3B8',
                    fontWeight: item.active ? '800' : '600', transition: 'all 0.2s', cursor: 'pointer'
                  }}>
                    {item.icon}
                    <span style={{ flex: 1 }}>{item.label}</span>
                    {item.badge > 0 && <div style={{ backgroundColor: '#EF4444', color: '#FFF', padding: '2px 8px', borderRadius: '8px', fontSize: '11px', fontWeight: '900' }}>{item.badge}</div>}
                  </div>
                </Link>
             ))}
          </nav>
        </aside>

        {/* Main Content */}
        <main style={{ flex: 1, padding: '40px 60px' }}>
          <header style={{ marginBottom: '48px' }}>
             <h1 style={{ fontSize: '32px', fontWeight: '1000', margin: 0, letterSpacing: '-1px' }}>Listing Approvals</h1>
             <p style={{ color: '#94A3B8', fontWeight: '600', marginTop: '8px' }}>Review and verify documentation for new service partners</p>
          </header>

          {data.length === 0 ? (
            <div style={{ backgroundColor: '#1E293B', borderRadius: '32px', padding: '80px 40px', textAlign: 'center', border: '1px solid rgba(255,255,255,0.05)' }}>
               <FiCheckCircle size={64} color="#10B981" />
               <h3 style={{ fontSize: '24px', fontWeight: '900', marginTop: '24px' }}>Queue is Clear</h3>
               <p style={{ color: '#94A3B8', marginTop: '12px' }}>All submitted businesses have been successfully verified.</p>
            </div>
          ) : (
            <div style={{ display: 'grid', gridTemplateColumns: 'minmax(0, 1fr)', gap: '24px' }}>
              {data.map(item => (
                <div key={item.id} style={{ 
                  backgroundColor: '#1E293B', borderRadius: '28px', overflow: 'hidden', border: '1px solid rgba(255,255,255,0.05)',
                  display: 'flex', transition: 'transform 0.2s'
                }}>
                  <div style={{ width: '220px', height: '100%', minHeight: '200px' }}>
                    <img src={item.image} alt={item.name || 'Business listing'} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                  </div>
                  <div style={{ padding: '32px', flex: 1, display: 'flex', flexDirection: 'column' }}>
                     <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                        <div>
                           <h3 style={{ fontSize: '22px', fontWeight: '900', margin: 0 }}>{item.name}</h3>
                           <p style={{ color: '#94A3B8', fontSize: '14px', fontWeight: '700', marginTop: '4px' }}>👤 PROWNER: {item.owner_name}</p>
                        </div>
                        <div style={{ backgroundColor: 'rgba(30,64,175,0.1)', color: 'var(--color-primary)', padding: '6px 12px', borderRadius: '10px', fontSize: '11px', fontWeight: '900' }}>
                           {item.category_name.toUpperCase()}
                        </div>
                     </div>

                     <div style={{ marginTop: 'auto', display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderTop: '1px solid rgba(255,255,255,0.05)', paddingTop: '20px' }}>
                        <div style={{ display: 'flex', gap: '20px' }}>
                           <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: '#64748B', fontSize: '12px', fontWeight: '700' }}>
                              <FiClock /> {new Date(item.createdAt).toLocaleDateString()}
                           </div>
                           <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: '#10B981', fontSize: '12px', fontWeight: '700' }}>
                              <FiCheckCircle /> KYC Verified
                           </div>
                        </div>
                        <button 
                          onClick={() => setSelectedBiz(item)}
                          style={{ backgroundColor: '#FFF', color: '#1E293B', border: 'none', padding: '10px 24px', borderRadius: '12px', fontWeight: '900', cursor: 'pointer' }}
                        >
                          Review Entry
                        </button>
                     </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </main>
      </div>

      {/* Detail Overlay */}
      {selectedBiz && (
        <div style={{ position: 'fixed', inset: 0, backgroundColor: 'rgba(15,23,42,0.9)', zIndex: 1000, display: 'flex', justifyContent: 'center', alignItems: 'center', padding: '20px' }}>
           <div style={{ backgroundColor: '#1E293B', borderRadius: '32px', width: '100%', maxWidth: '650px', padding: '40px', border: '1px solid rgba(255,255,255,0.1)' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '32px' }}>
                 <div>
                    <h2 style={{ fontSize: '28px', fontWeight: '900', margin: 0 }}>Business Verification</h2>
                    <p style={{ color: '#94A3B8', fontWeight: '600', marginTop: '4px' }}>Case ID: LH-VER-00{selectedBiz.id}</p>
                 </div>
                 <button onClick={() => setSelectedBiz(null)} style={{ background: 'none', border: 'none', color: '#94A3B8', cursor: 'pointer' }}><FiX size={32} /></button>
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '32px', marginBottom: '40px' }}>
                 <div>
                    <img src={selectedBiz.image} alt={selectedBiz.name || 'Selected business'} style={{ width: '100%', borderRadius: '24px', height: '180px', objectFit: 'cover' }} />
                    <div style={{ marginTop: '20px', display: 'flex', gap: '8px' }}>
                       <div style={{ backgroundColor: 'rgba(255,255,255,0.05)', padding: '10px', borderRadius: '12px', flex: 1, textAlign: 'center' }}>
                          <FiImage color="#94A3B8" />
                       </div>
                       <div style={{ backgroundColor: 'rgba(255,255,255,0.05)', padding: '10px', borderRadius: '12px', flex: 1, textAlign: 'center' }}>
                          <FiActivity color="#94A3B8" />
                       </div>
                    </div>
                 </div>
                 <div>
                    <div style={{ marginBottom: '20px' }}>
                       <span style={{ fontSize: '11px', fontWeight: '900', color: '#64748B', letterSpacing: '1px' }}>NAME</span>
                       <div style={{ fontSize: '18px', fontWeight: '800', marginTop: '4px' }}>{selectedBiz.name}</div>
                    </div>
                    <div style={{ marginBottom: '20px' }}>
                       <span style={{ fontSize: '11px', fontWeight: '900', color: '#64748B', letterSpacing: '1px' }}>PROVIDER</span>
                       <div style={{ fontSize: '18px', fontWeight: '800', marginTop: '4px' }}>{selectedBiz.owner_name}</div>
                    </div>
                    <div>
                       <span style={{ fontSize: '11px', fontWeight: '900', color: '#64748B', letterSpacing: '1px' }}>SUBMITTED ON</span>
                       <div style={{ fontSize: '16px', fontWeight: '700', marginTop: '4px' }}>{new Date(selectedBiz.createdAt).toDateString()}</div>
                    </div>
                 </div>
              </div>

              <div style={{ display: 'flex', gap: '16px' }}>
                 <button 
                  onClick={() => handleAction(selectedBiz.id, 'reject')}
                  style={{ flex: 1, padding: '20px', borderRadius: '20px', backgroundColor: 'rgba(239, 68, 68, 0.1)', color: '#EF4444', border: '1.5px solid rgba(239, 68, 68, 0.3)', fontWeight: '900', cursor: 'pointer' }}
                 >REJECT LISTING</button>
                 <button 
                  onClick={() => handleAction(selectedBiz.id, 'approve')}
                  style={{ flex: 1, padding: '20px', borderRadius: '20px', backgroundColor: 'var(--color-primary)', color: '#FFF', border: 'none', fontWeight: '900', cursor: 'pointer', boxShadow: '0 8px 24px rgba(30,64,175,0.3)' }}
                 >VERIFY & GO LIVE</button>
              </div>
           </div>
        </div>
      )}

    </div>
  );
}

'use client';
import React, { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useSelector } from 'react-redux';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  FiHexagon, FiUsers, FiBriefcase, FiTrendingUp, FiCheckCircle, 
  FiClock, FiAlertTriangle, FiArrowRight, FiActivity, FiLayers, FiShield, FiBell, FiSettings, FiExternalLink, FiSearch
} from 'react-icons/fi';
import adminService from '../../../services/adminService';
import Link from 'next/link';

export default function AdminDashboardPage() {
  const router = useRouter();
  const { isAuthenticated, user } = useSelector((state) => state.auth);

  const [stats, setStats] = useState({ users: 1560, providers: 428, revenue: 145000 });
  const [pendingCount, setPendingCount] = useState(5);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!isAuthenticated || user?.role !== 'admin') {
      router.push('/login');
    } else {
      fetchAdminData();
    }
  }, [isAuthenticated, user]);

  const fetchAdminData = async () => {
    setLoading(true);
    try {
      const [statsRes, pendingRes] = await Promise.all([
        adminService.getPlatformStats().catch(() => ({ data: { users: 1560, providers: 428, revenue: 145000 } })),
        adminService.getPendingBusinesses().catch(() => ({ data: [1,2,3,4,5] }))
      ]);
      setStats(statsRes.data || statsRes);
      setPendingCount((pendingRes.data || pendingRes).length || 0);
    } catch (e) {
      console.error('Admin fetch error:', e);
    } finally {
      setLoading(false);
    }
  };

  if (loading) return (
    <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center p-10">
       <div className="w-12 h-12 border-4 border-indigo-500/20 border-t-indigo-500 rounded-full animate-spin mb-6" />
       <p className="text-slate-500 font-black uppercase tracking-widest text-[10px]">Accessing LocalHub+ Admin Vault...</p>
    </div>
  );

  return (
    <div className="bg-slate-950 min-h-screen flex text-slate-200">

      {/* 1. Global Command Sidebar */}
      <aside className="w-80 bg-slate-900 border-r border-white/5 sticky top-0 h-screen hidden lg:flex flex-col p-10 z-50">
        <div className="flex items-center gap-4 mb-16">
          <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center shadow-glow text-white">
            <FiHexagon size={24} />
          </div>
          <div>
            <h2 className="text-xl font-black text-white tracking-tighter leading-none">AdminHub</h2>
            <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mt-1">v4.0.2 Stable</p>
          </div>
        </div>

        <nav className="flex-grow space-y-2">
           {[
             { label: 'Dashboard', ic: <FiLayers />, active: true, route: '/admin/dashboard' },
             { label: 'Approvals', ic: <FiCheckCircle />, badge: pendingCount, active: false, route: '/admin/approvals' },
             { label: 'User Index', ic: <FiUsers />, active: false, route: '/admin/users' },
             { label: 'Partners', ic: <FiBriefcase />, active: false, route: '/admin/businesses' },
             { label: 'System Logs', ic: <FiActivity />, active: false, route: '/admin/reports' },
             { label: 'Categories', ic: <FiSettings />, active: false, route: '/admin/categories' },
           ].map(item => (
             <motion.div key={item.label} whileHover={{ x: 4 }}>
               <Link href={item.route} className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all ${
                 item.active ? 'bg-indigo-600 text-white shadow-glow' : 'text-slate-500 hover:text-white hover:bg-white/5'
               }`}>
                 {item.ic} <span className="flex-grow">{item.label}</span>
                 {item.badge > 0 && (
                   <span className="bg-red-500 text-white px-2 py-0.5 rounded-lg text-[9px]">{item.badge}</span>
                 )}
               </Link>
             </motion.div>
           ))}
        </nav>

        <div className="pt-8 border-t border-white/5">
           <button onClick={() => router.push('/')} className="w-full flex items-center gap-4 px-6 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest text-slate-400 hover:bg-white/5 hover:text-white transition-all">
             <FiExternalLink /> View Marketplace
           </button>
        </div>
      </aside>

      <main className="flex-grow flex flex-col min-w-0">

        {/* Top Control Bar */}
        <header className="bg-slate-900/50 backdrop-blur-xl border-b border-white/5 sticky top-0 z-[100] py-6 shadow-subtle px-10">
          <div className="flex justify-between items-center">
             <div>
               <h1 className="text-3xl font-black text-white tracking-tighter">Executive Management</h1>
               <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mt-1 flex items-center gap-2">
                 <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
                 Global Systems Online
               </p>
             </div>
             <div className="flex items-center gap-6">
                <div className="hidden md:flex relative group">
                  <FiSearch className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" />
                  <input placeholder="Search records..." className="bg-white/5 border border-white/10 pl-11 pr-6 py-3 rounded-2xl text-xs font-bold outline-none focus:border-indigo-500 transition-all w-64" />
                </div>
               <div className="flex items-center gap-3">
                 <button className="w-12 h-12 rounded-2xl bg-white/5 border border-white/10 flex items-center justify-center text-slate-400 hover:text-white hover:border-white/20 transition-all relative">
                    <FiBell size={20} />
                    <div className="absolute top-3.5 right-3.5 w-2 h-2 bg-red-500 rounded-full border-2 border-slate-900" />
                 </button>
                 <div className="w-12 h-12 rounded-2xl bg-indigo-600/10 border border-indigo-600/20 flex items-center justify-center text-indigo-400">
                    <FiShield size={20} />
                 </div>
               </div>
             </div>
          </div>
        </header>

        <div className="p-8 md:p-12 max-w-7xl w-full mx-auto">

          {/* Main KPI Dashboard */}
          <section className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-6 mb-12">
            {[
              { label: 'Active Consumer Base', value: stats.users.toLocaleString(), trend: '+4.2%', icon: <FiUsers />, color: 'text-indigo-500', bg: 'bg-indigo-500/5' },
              { label: 'Verified Service Partners', value: stats.providers.toLocaleString(), trend: '+1.5%', icon: <FiBriefcase />, color: 'text-emerald-500', bg: 'bg-emerald-500/5' },
              { label: 'Marketplace Revenue', value: `₹${stats.revenue.toLocaleString()}`, trend: '+12.8%', icon: <FiTrendingUp />, color: 'text-amber-500', bg: 'bg-amber-500/5' },
              { label: 'Pending Approval', value: pendingCount.toString(), trend: 'Needs Review', icon: <FiClock />, color: 'text-rose-500', bg: 'bg-rose-500/5' },
            ].map((kpi, idx) => (
              <motion.div 
                key={kpi.label}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: idx * 0.1 }}
                whileHover={{ y: -5, borderColor: 'rgba(99, 102, 241, 0.2)' }}
                className={`group relative bg-white/5 p-10 rounded-[48px] border border-white/5 shadow-2xl overflow-hidden`}
              >
                {/* Visual Flair */}
                <div className={`absolute -bottom-8 -right-8 opacity-5 text-9xl ${kpi.color} group-hover:rotate-12 transition-transform`}>
                  {kpi.icon}
                </div>

                <div className={`w-14 h-14 rounded-2xl ${kpi.bg} ${kpi.color} flex items-center justify-center mb-8 shadow-inner`}>
                  {kpi.icon}
                </div>
                <div className="flex items-end justify-between">
                   <div>
                     <div className="text-4xl font-black text-white tracking-tighter mb-2">{kpi.value}</div>
                     <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{kpi.label}</div>
                   </div>
                   <div className="text-[10px] font-black text-emerald-500 bg-emerald-500/10 px-3 py-1.5 rounded-xl border border-emerald-500/10">
                     {kpi.trend}
                   </div>
                </div>
              </motion.div>
            ))}
          </section>

          {/* Quick Action Grid (parity with mobile admin dashboard) */}
          <section className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-4 mb-14">
            {[
              { label: 'Users', icon: <FiUsers />, route: '/admin/users' },
              { label: 'Businesses', icon: <FiBriefcase />, route: '/admin/businesses' },
              { label: 'Approvals', icon: <FiCheckCircle />, route: '/admin/approvals' },
              { label: 'Categories', icon: <FiSettings />, route: '/admin/categories' },
              { label: 'Reports', icon: <FiActivity />, route: '/admin/reports' },
            ].map((item) => (
              <button
                key={item.label}
                onClick={() => router.push(item.route)}
                className="bg-white/5 border border-white/10 rounded-2xl p-4 text-left hover:bg-white/10 transition-colors"
              >
                <div className="w-10 h-10 rounded-xl bg-indigo-500/10 text-indigo-300 flex items-center justify-center mb-3">
                  {item.icon}
                </div>
                <p className="text-sm font-bold text-slate-100">{item.label}</p>
              </button>
            ))}
          </section>

          {/* Action Grids */}
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

             {/* Pending Approvals Section */}
             <div className="lg:col-span-8">
               <section className="bg-white/5 p-10 rounded-[48px] border border-white/5 shadow-premium">
                 <div className="flex justify-between items-center mb-10">
                   <h3 className="text-2xl font-black text-white tracking-tighter flex items-center gap-3">
                     <FiCheckCircle className="text-indigo-500" /> Pending Approvals
                   </h3>
                   <Link href="/admin/approvals" className="text-indigo-400 font-black text-[10px] uppercase tracking-widest hover:text-indigo-300 transition-colors">
                     Review Managed Queue →
                   </Link>
                 </div>

                 {pendingCount > 0 ? (
                   <motion.div 
                    whileHover={{ scale: 1.01 }}
                    className="bg-red-500/10 border border-red-500/20 p-10 rounded-[40px] flex flex-col md:flex-row items-center gap-10"
                   >
                     <div className="w-20 h-20 bg-red-500 rounded-3xl flex items-center justify-center shadow-glow-red flex-shrink-0 animate-pulse">
                        <FiClock size={36} className="text-white" />
                     </div>
                     <div className="flex-grow text-center md:text-left">
                        <h4 className="text-2xl font-black text-red-500 tracking-tight leading-none mb-3">{pendingCount} Business Verifications Critical</h4>
                        <p className="text-slate-400 text-sm font-medium pr-10">High-priority verification backlog detected. Providers are awaiting activation to begin Marketplace transactions.</p>
                     </div>
                     <button 
                       onClick={() => router.push('/admin/approvals')}
                       className="bg-red-500 text-white px-10 py-5 rounded-2xl font-black text-[10px] uppercase tracking-[0.2em] shadow-glow flex-shrink-0 hover:brightness-110 transition-all"
                     >
                       Begin Batch Review
                     </button>
                   </motion.div>
                 ) : (
                   <div className="flex flex-col items-center justify-center py-20 bg-slate-900/50 rounded-[40px] border border-dashed border-white/5 text-slate-500">
                      <FiCheckCircle size={48} className="text-emerald-500 mb-6" />
                      <p className="font-bold uppercase tracking-widest text-[10px]">Registry queue cleared</p>
                   </div>
                 )}
               </section>
             </div>

             {/* Security Feed */}
             <div className="lg:col-span-4">
               <section className="bg-white/5 p-10 rounded-[48px] border border-white/5 shadow-premium h-full">
                  <h3 className="text-xl font-black text-white tracking-tighter mb-8 flex items-center gap-3">
                    <FiShield className="text-indigo-500" /> Threat Intelligence
                  </h3>
                  <div className="space-y-6">
                    {[
                      { color: 'bg-amber-500', text: 'Suspicious login: Pune, MH', time: '12m ago' },
                      { color: 'bg-emerald-500', text: 'Global Ledger Backup Successful', time: '2h ago' },
                      { color: 'bg-indigo-500', text: 'Security Keys Rotated', time: '5h ago' },
                      { color: 'bg-slate-500', text: 'Stripe Webhook Verified', time: '14h ago' }
