export default function ChatDetailPage() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const chatName = searchParams?.get('name') || 'Elite Specialist';

  const [message, setMessage] = useState('');
  const [messages, setMessages] = useState([
    { id: '1', text: 'Hello, are you available today for a plumbing leak?', sender: 'other', time: '10:30 AM', status: 'read' },
    { id: '2', text: 'Yes, I can come by at around 2 PM to assess the damage.', sender: 'me', time: '10:35 AM', status: 'read' },
    { id: '3', text: 'That works great! I have the parts ready in the garage.', sender: 'other', time: '10:40 AM', status: 'read' },
  ]);
  const messagesEndRef = useRef(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = () => {
    if (message.trim() === '') return;

    const newMessage = {
      id: Date.now().toString(),
      text: message,
      sender: 'me',
      time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      status: 'sent'
    };

    setMessages([...messages, newMessage]);
    setMessage('');

    setTimeout(scrollToBottom, 100);
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="bg-bg-main h-screen flex flex-col overflow-hidden">

      {/* 1. Precision Chat Header */}
      <header className="bg-white/80 backdrop-blur-xl border-b border-slate-200 py-4 px-6 z-[100] shadow-premium">
        <div className="section-container max-w-4xl flex items-center justify-between">
          <div className="flex items-center gap-5">
            <motion.button 
              whileHover={{ x: -4 }}
              onClick={() => router.back()} 
              className="w-11 h-11 rounded-2xl border border-slate-200 flex items-center justify-center text-slate-500 hover:text-primary transition-all"
            >
              <FiChevronLeft size={24} />
            </motion.button>
            <div className="flex items-center gap-4">
              <div className="relative">
                <div className="w-12 h-12 rounded-2xl overflow-hidden border-2 border-white shadow-subtle bg-slate-100">
                  <img src={`https://ui-avatars.com/api/?name=${chatName}&background=4f46e5&color=fff`} className="w-full h-full object-cover" alt="Profile" />
                </div>
                <div className="absolute -bottom-1 -right-1 w-4 h-4 rounded-full bg-emerald-500 border-2 border-white" />
              </div>
              <div>
                <h2 className="text-lg font-black text-slate-900 tracking-tight leading-none mb-1">{chatName}</h2>
                <div className="flex items-center gap-2">
                  <span className="text-[10px] font-black text-emerald-500 uppercase tracking-widest animate-pulse">Active Now</span>
                </div>
              </div>
            </div>
          </div>
          <motion.button 
            whileHover={{ scale: 1.1 }}
            className="w-11 h-11 rounded-2xl bg-slate-50 border border-slate-100 flex items-center justify-center text-slate-400 hover:text-primary transition-all"
          >
            <FiMoreVertical size={20} />
          </motion.button>
        </div>
      </header>

      {/* 2. Chat Canvas */}
      <div className="flex-grow overflow-y-auto no-scrollbar scroll-smooth">
        <div className="section-container max-w-4xl py-12 px-6">

          <div className="flex flex-col items-center mb-10">
            <div className="inline-flex items-center gap-2 bg-white/50 border border-slate-100 px-5 py-2 rounded-full text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] shadow-sm">
               <FiShield size={14} className="text-emerald-500" /> Secure Encryption Active
            </div>
            <p className="text-[10px] text-slate-300 font-bold mt-4 uppercase tracking-[0.1em]">CONVERSATION ESTABLISHED MARCH 2024</p>
          </div>

          <div className="flex flex-col gap-8">
            <AnimatePresence mode="popLayout">
              {messages.map((msg, idx) => {
                const isMe = msg.sender === 'me';
                return (
                  <motion.div 
                    key={msg.id}
                    layout
                    initial={{ opacity: 0, x: isMe ? 20 : -20, scale: 0.95 }}
                    animate={{ opacity: 1, x: 0, scale: 1 }}
                    className={`flex flex-col ${isMe ? 'items-end' : 'items-start'}`}
                  >
                     <div className={`max-w-[80%] md:max-w-[70%] px-6 py-4 rounded-[32px] shadow-subtle ${
                       isMe 
                        ? 'bg-slate-900 text-white rounded-br-lg' 
                        : 'bg-white text-slate-800 border border-slate-50 rounded-bl-lg'
                     }`}>
                        <p className="text-[15px] font-medium leading-relaxed">{msg.text}</p>
                     </div>
                     <div className={`mt-3 flex items-center gap-2 text-[10px] font-black text-slate-300 uppercase tracking-widest ${isMe ? 'flex-row-reverse' : 'flex-row'}`}>
                        {msg.time} 
                        {isMe && (
                          <FiCheckCircle className={msg.status === 'read' ? 'text-primary' : 'text-slate-200'} size={14} />
                        )}
                     </div>
                  </motion.div>
                );
              })}
            </AnimatePresence>
            <div ref={messagesEndRef} className="h-4" />
          </div>
        </div>
      </div>

      {/* 3. Elite Composition Footer */}
      <footer className="bg-white/80 backdrop-blur-xl border-t border-slate-200 p-6 z-[100]">
        <div className="section-container max-w-4xl">
           <div className="flex items-end gap-4">
              <motion.button 
                whileHover={{ scale: 1.05, backgroundColor: 'rgba(79, 70, 229, 0.05)' }}
                className="w-14 h-14 rounded-2xl bg-slate-50 border border-slate-100 flex items-center justify-center text-slate-400 hover:text-primary transition-all flex-shrink-0"
              >
                <FiPaperclip size={22} />
              </motion.button>

              <div className="flex-grow flex items-end gap-4 bg-slate-50 rounded-3xl border border-slate-100 p-2.5 focus-within:bg-white focus-within:border-primary focus-within:ring-4 focus-within:ring-primary/5 transition-all shadow-inner group">
                <textarea 
                  value={message}
                  onChange={(e) => {
                    setMessage(e.target.value);
                    e.target.style.height = 'auto';
                    e.target.style.height = Math.min(e.target.scrollHeight, 120) + 'px';
                  }}
                  onKeyDown={handleKeyDown}
                  placeholder="Draft your secure message..."
                  className="flex-grow bg-transparent border-none outline-none pl-4 py-3 text-slate-800 font-semibold text-[15px] resize-none min-h-[48px] max-h-[120px] no-scrollbar"
                />
                <motion.button 
                  disabled={!message.trim()}
                  whileHover={message.trim() ? { scale: 1.05 } : {}}
                  whileTap={message.trim() ? { scale: 0.95 } : {}}
                  onClick={handleSend}
                  className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all shadow-glow-primary ${
                    message.trim() 
                      ? 'bg-primary text-white' 
                      : 'bg-slate-200 text-slate-400'
                  }`}
                >
                  <FiSend size={22} />
                </motion.button>
              </div>
           </div>
           <p className="text-center mt-4 text-[9px] font-black text-slate-300 uppercase tracking-[0.4em]">
             LOCAL-HUB END-TO-END SECURE CHANNEL
           </p>
        </div>
      </footer>
    </div>
  );
}

'use client';
import React, { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  FiSearch, FiEdit3, FiArrowLeft, FiMessageCircle, FiChevronRight, FiClock, FiCheck, FiMoreHorizontal, FiChevronLeft
} from 'react-icons/fi';
import chatService from '../../services/chatService';
import Link from 'next/link';

export default function InboxPage() {
  const router = useRouter();
  const [search, setSearch] = useState('');
  const [chats, setChats] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchChats();
  }, []);

  const fetchChats = async () => {
    setLoading(true);
    try {
      const res = await chatService.getChats().catch(() => ({ data: [] }));
      let fetchedChats = res.data || res || [];

      if (fetchedChats.length === 0) {
        fetchedChats = [
          { id: '1', name: 'Rahul Kumar', time: '10:45 AM', lastMessage: 'Thank you! The AC is working perfectly now.', unread: 2, isOnline: true },
          { id: '2', name: 'Sneha Patel', time: 'Yesterday', lastMessage: 'Can you share the pricing details?', unread: 0, isOnline: false },
          { id: '3', name: 'Amit Singh', time: 'Mon', lastMessage: 'See you tomorrow at 2 PM.', unread: 0, isOnline: true },
        ];
      }
      setChats(fetchedChats);
    } catch (e) {
      console.log('Error fetching chats:', e);
    } finally {
      setLoading(false);
    }
  };

  const filteredChats = chats.filter(c => c.name.toLowerCase().includes(search.toLowerCase()));

  return (
    <div className="bg-bg-main min-h-screen flex flex-col">

      {/* 1. Immersive Navigation Header */}
      <header className="bg-white/80 backdrop-blur-xl border-b border-slate-200 sticky top-0 z-[100] py-6 shadow-premium">
        <div className="section-container max-w-4xl flex justify-between items-center">
          <div className="flex items-center gap-6">
            <motion.button 
              whileHover={{ x: -4 }}
              onClick={() => router.back()} 
              className="w-11 h-11 rounded-2xl border border-slate-200 flex items-center justify-center text-slate-500 hover:text-primary transition-all"
            >
              <FiChevronLeft size={24} />
            </motion.button>
            <div>
              <h1 className="text-3xl font-black text-slate-900 tracking-tighter">Secure Inbox</h1>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mt-1 flex items-center gap-2">
                 <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
                 End-to-end encrypted
              </p>
            </div>
          </div>
          <motion.button 
            whileHover={{ scale: 1.05, rotate: 5 }}
            whileTap={{ scale: 0.95 }}
            className="w-12 h-12 rounded-2xl bg-primary text-white shadow-glow flex items-center justify-center"
          >
            <FiEdit3 size={20} />
          </motion.button>
        </div>
      </header>

      <main className="section-container max-w-4xl pt-10 pb-32">

        {/* 2. Precision Search Cluster */}
        <div className="relative group mb-12">
          <FiSearch className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-primary transition-colors text-xl" />
          <input 
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search by professional name..."
            className="w-full pl-16 pr-8 py-5 rounded-[24px] border border-slate-100 bg-white/50 focus:bg-white focus:border-primary focus:ring-4 focus:ring-primary/5 outline-none transition-all font-semibold text-slate-800 shadow-subtle group-focus-within:shadow-premium"
          />
        </div>

        {/* 3. Messaging Ledger */}
        <div className="space-y-4">
          {loading ? (
             <div className="flex flex-col items-center justify-center py-20 bg-white/50 rounded-[40px] border border-dashed border-slate-200">
                <div className="w-10 h-10 rounded-full border-4 border-primary/20 border-t-primary animate-spin mb-6" />
                <p className="text-slate-400 font-black uppercase tracking-[0.2em] text-[10px]">Synchronizing Cloud Messages...</p>
             </div>
          ) : filteredChats.length === 0 ? (
            <motion.div 
              initial={{ opacity: 0, scale: 0.95 }}
              animate={{ opacity: 1, scale: 1 }}
              className="text-center p-24 bg-white rounded-[40px] border border-slate-100 shadow-premium"
            >
              <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-10 border border-slate-100 shadow-inner">
                <FiMessageCircle size={40} className="text-slate-200" />
              </div>
              <h2 className="text-3xl font-black text-slate-900 tracking-tighter mb-4">Silent Inbox</h2>
              <p className="text-slate-500 font-medium max-w-xs mx-auto mb-12">
                When you hire an expert or receive service updates, your private conversations will appear here.
              </p>
              <button 
                onClick={() => router.push('/search')}
                className="btn-premium px-12 py-4 !rounded-2xl"
              >
                Hire a Professional
              </button>
            </motion.div>
          ) : (
            <AnimatePresence mode="popLayout">
              {filteredChats.map((chat, idx) => {
                const hasUnread = chat.unread > 0;
                return (
                  <motion.div 
                    key={chat.id}
                    layout
                    initial={{ opacity: 0, y: 15 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: idx * 0.05 }}
                    onClick={() => router.push(`/inbox/${chat.id}?name=${encodeURIComponent(chat.name)}`)}
                    className={`group relative bg-white px-8 py-7 rounded-[32px] border transition-all flex items-center gap-6 cursor-pointer hover:shadow-premium hover:-translate-y-1 ${
                      hasUnread ? 'border-primary/20 shadow-glow-primary/5' : 'border-slate-100 shadow-subtle'
                    }`}
                  >
                    <div className="relative">
                      <div className="w-20 h-20 rounded-[28px] overflow-hidden bg-slate-100 border-4 border-white shadow-subtle">
                         <img 
                          src={`https://ui-avatars.com/api/?name=${chat.name}&background=4f46e5&color=fff`} 
                          className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" 
                          alt={chat.name} 
                         />
                      </div>
                      {chat.isOnline && (
                        <div className="absolute -bottom-1 -right-1 w-6 h-6 rounded-full bg-emerald-500 border-4 border-white shadow-sm flex items-center justify-center">
                           <div className="w-2 h-2 rounded-full bg-white animate-pulse" />
                        </div>
                      )}
                    </div>

                    <div className="flex-grow min-w-0">
                      <div className="flex justify-between items-center mb-1">
                         <h3 className="text-xl font-black text-slate-900 tracking-tight leading-none truncate">{chat.name}</h3>
                         <span className={`text-[10px] font-black uppercase tracking-widest ${hasUnread ? 'text-primary' : 'text-slate-300'}`}>
                           {chat.time}
                         </span>
                      </div>
                      <div className="flex justify-between items-center">
                         <p className={`text-sm truncate pr-4 ${hasUnread ? 'text-slate-900 font-black' : 'text-slate-400 font-medium'}`}>
                           {chat.lastMessage}
                         </p>
                         {hasUnread && (
                           <motion.div 
                             initial={{ scale: 0 }} 
                             animate={{ scale: 1 }}
                             className="bg-primary px-3 py-1 rounded-full text-white text-[10px] font-black shadow-glow"
                           >
                             {chat.unread}
                           </motion.div>
                         )}
                      </div>
                    </div>
                    <FiChevronRight className="text-slate-200 group-hover:text-primary transition-colors flex-shrink-0" size={24} />
                  </motion.div>
                )
              })}
            </AnimatePresence>
          )}
        </div>
      </main>

      {/* Floating Global Action */}
      <div className="fixed bottom-10 right-10 z-[110]">
         <motion.button 
           whileHover={{ scale: 1.1, rotate: 10 }}
           whileTap={{ scale: 0.9 }}
           className="w-16 h-16 rounded-full bg-slate-900 text-white shadow-2xl flex items-center justify-center border border-white/10"
         >
           <FiMoreHorizontal size={24} />
         </motion.button>
      </div>
    </div>
  );
}

