                            <div>
                               <h4 className="text-xl font-black text-slate-900 tracking-tighter leading-none mb-2">{lead.service || 'Priority Service'}</h4>
                               <div className="flex flex-wrap items-center gap-4 text-xs font-bold text-slate-400">
