                                  <span className="flex items-center gap-1.5"><FiClock className="text-primary-light" /> {lead.time}</span>
                                  <span className="flex items-center gap-1.5"><FiMapPin className="text-primary-light" /> {lead.address}</span>
                               </div>
                            </div>
