'use client';
import React, { useState, useEffect } from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { useSelector, useDispatch } from 'react-redux';
import { motion, AnimatePresence } from 'framer-motion';
import { FiMenu, FiX, FiBell, FiUser, FiMapPin, FiSearch, FiHeart, FiHexagon } from 'react-icons/fi';
import { logoutUser } from '../store/authSlice';

const NAV_LINKS = [
  { name: 'Home', path: '/' },
  { name: 'Categories', path: '/categories' },
  { name: 'Requests', path: '/requests' },
  { name: 'Favorites', path: '/favorites' },
];

export default function Navbar() {
  const dispatch = useDispatch();
  const pathname = usePathname();
  const { isAuthenticated, user } = useSelector((state) => state.auth);

  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleLogout = () => {
    dispatch(logoutUser());
  };

  const dashboardPath =
    user?.role === 'admin'
      ? '/admin/dashboard'
      : user?.role === 'provider'
        ? '/provider/dashboard'
        : '/profile';

  return (
    <nav
      className={`fixed top-0 left-0 right-0 z-[100] transition-all duration-500 ${
        isScrolled 
          ? 'py-3 backdrop-blur-xl bg-white/85 shadow-premium border-b border-slate-200/50'
          : 'py-4 bg-transparent'
      }`}
    >
      <div className="section-container flex items-center justify-between min-h-[64px]">

        {/* Logo */}
        <Link href="/" className="flex items-center gap-3 group">
          <div className="w-10 h-10 bg-primary rounded-2xl flex items-center justify-center shadow-glow group-hover:rotate-12 transition-transform duration-300">
            <FiHexagon className="text-white text-xl" />
          </div>
          <span className="text-2xl font-black text-slate-900 tracking-tighter">
            Local<span className="text-primary italic">Hub</span>
          </span>
        </Link>

        {/* Desktop Navigation */}
        <div className="hidden lg:flex items-center gap-8">
          {NAV_LINKS.map((link) => {
            const isActive = pathname === link.path;
            return (
              <Link key={link.path} href={link.path} className="relative group p-2">
                <span size="sm" className={`text-sm font-bold tracking-wide transition-colors duration-300 ${
                  isActive ? 'text-primary' : 'text-slate-600 group-hover:text-primary'
                }`}>
                  {link.name}
                </span>
                {isActive && (
                  <motion.div 
                    layoutId="nav-underline"
                    className="absolute bottom-0 left-0 right-0 h-1 bg-primary rounded-full"
                  />
                )}
                {!isActive && (
                  <div className="absolute bottom-0 left-1/2 -translate-x-1/2 w-0 h-1 bg-primary rounded-full group-hover:w-full transition-all duration-300" />
                )}
              </Link>
            );
          })}
        </div>

        {/* Right Side Actions */}
        <div className="flex items-center gap-3">
          {/* Notifications / Search (Desktop Only) */}
          <div className="hidden md:flex items-center gap-2 mr-2">
            <button title="Search" className="w-11 h-11 rounded-2xl bg-slate-50 border border-slate-100 flex items-center justify-center text-slate-500 hover:bg-white hover:text-primary hover:shadow-subtle transition-all">
              <FiSearch size={20} />
            </button>
            <button title="Notifications" className="w-11 h-11 rounded-2xl bg-slate-50 border border-slate-100 flex items-center justify-center text-slate-500 hover:bg-white hover:text-primary hover:shadow-subtle relative transition-all">
              <FiBell size={20} />
              <div className="absolute top-3 right-3 w-2 h-2 bg-red-500 rounded-full border-2 border-slate-50" />
            </button>
          </div>

          {isAuthenticated ? (
            <div className="flex items-center gap-3">
              {(user?.role === 'admin' || user?.role === 'provider') && (
                <Link
                  href={dashboardPath}
                  className="hidden md:flex text-xs font-black uppercase tracking-widest text-primary bg-primary/10 border border-primary/20 px-4 py-2 rounded-xl"
                >
                  Dashboard
                </Link>
              )}
              <Link href="/profile" className="flex items-center gap-3 bg-slate-50 p-1.5 pr-4 rounded-[20px] border border-slate-100 hover:bg-white hover:shadow-subtle transition-all group">
                <div className="w-9 h-9 rounded-[14px] overflow-hidden bg-primary/10 border border-primary/20 flex items-center justify-center">
                  {user?.avatar ? (
                    <img src={user.avatar} className="w-full h-full object-cover" alt="avatar" />
                  ) : (
                    <FiUser className="text-primary" />
                  )}
                </div>
                <div className="hidden lg:block text-left">
                  <p className="text-xs font-black text-slate-900 leading-tight truncate max-w-[100px]">
                    {user?.name || 'User'}
                  </p>
                  <p className="text-[10px] font-bold text-primary uppercase tracking-tighter">
                    {user?.role || 'Member'}
                  </p>
                </div>
              </Link>

              {/* Desktop Logout Button */}
              <button 
                onClick={handleLogout}
                className="hidden md:flex text-sm font-bold text-red-500 hover:text-red-600 px-3 transition-colors"
              >
                Logout
              </button>
            </div>
          ) : (
            <div className="flex items-center gap-3">
              <Link href="/login" className="text-sm font-black text-slate-600 hover:text-primary px-4 transition-colors btn-ui !py-2 !px-5">
                Login
              </Link>
              <Link href="/register" className="btn-premium btn-ui !px-5 !py-2.5 text-xs uppercase tracking-widest">
                Join Now
              </Link>
            </div>
          )}

          {/* Mobile Menu Toggle */}
          <button 
            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
            className="lg:hidden w-11 h-11 rounded-2xl bg-primary/10 text-primary flex items-center justify-center hover:bg-primary hover:text-white transition-all"
          >
            {isMobileMenuOpen ? <FiX size={22} /> : <FiMenu size={22} />}
          </button>
        </div>
      </div>

      {/* Mobile Menu Drawer */}
      <AnimatePresence>
        {isMobileMenuOpen && (
          <motion.div
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            className="lg:hidden absolute top-[100%] left-0 right-0 bg-white border-b border-slate-100 shadow-premium py-6 overflow-hidden"
          >
            <div className="section-container flex flex-col gap-4">
              {NAV_LINKS.map((link) => (
                <Link 
                  key={link.path} 
                  href={link.path} 
                  onClick={() => setIsMobileMenuOpen(false)}
                  className={`flex items-center justify-between p-4 rounded-2xl ${
                    pathname === link.path ? 'bg-primary/5 text-primary border border-primary/10' : 'bg-slate-50 text-slate-600'
                  }`}
                >
                  <span className="font-black text-base">{link.name}</span>
                  <FiHexagon size={16} />
                </Link>
              ))}

              {(user?.role === 'admin' || user?.role === 'provider') && (
                <Link
                  href={dashboardPath}
                  onClick={() => setIsMobileMenuOpen(false)}
                  className="flex items-center justify-between p-4 rounded-2xl bg-primary/5 text-primary border border-primary/10"
                >
                  <span className="font-black text-base">Dashboard</span>
                  <FiHexagon size={16} />
                </Link>
              )}

              {isAuthenticated && (
                <button 
                  onClick={() => {
                    handleLogout();
                    setIsMobileMenuOpen(false);
                  }}
                  className="flex items-center justify-between p-4 rounded-2xl bg-red-50 text-red-500 border border-red-100 mt-4"
                >
                  <span className="font-black text-base">Sign Out</span>
                  <FiUser size={16} />
                </button>
              )}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </nav>
  );
}

'use client';
import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { useRouter } from 'next/navigation';
import { renderDynamicIcon } from '../../utils/iconHelper';
import categoryService from '../../services/categoryService';
import businessService from '../../services/businessService';

export default function CategoryGrid() {
  const [categories, setCategories] = useState([]);
  const [topBusinesses, setTopBusinesses] = useState([]);
  const [loading, setLoading] = useState(true);
  const router = useRouter();

  useEffect(() => {
    async function fetchCategories() {
      try {
        const res = await categoryService.getCategories();
        const mainCats = (res.data || []).filter(cat => !cat.parent_id);
        setCategories(mainCats);
      } catch (err) {
        console.error('Failed to fetch categories:', err);
      } finally {
        setLoading(false);
      }
    }
    fetchCategories();
  }, []);

  useEffect(() => {
    async function fetchTopBusinesses() {
      try {
        const res = await businessService.getAllBusinesses({ featured: true });
        const rows = (res?.data || []).slice(0, 8);
        setTopBusinesses(rows);
      } catch (err) {
        console.error('Failed to fetch top businesses:', err);
      }
    }
    fetchTopBusinesses();
  }, []);

  const containerVariants = {
    hidden: { opacity: 0 },
    show: {
      opacity: 1,
      transition: { staggerChildren: 0.05 }
    }
  };

  const itemVariants = {
    hidden: { y: 20, opacity: 0 },
    show: { y: 0, opacity: 1 }
  };

  if (loading) {
    return (
      <div className="mb-12 md:mb-16 grid grid-cols-2 md:grid-cols-4 lg:grid-cols-8 gap-4 md:gap-6">
        {[1, 2, 3, 4, 5, 6, 7, 8].map((i) => (
          <div key={i} className="flex flex-col items-center gap-4">
            <div className="w-20 h-20 rounded-full skeleton" />
            <div className="w-16 h-4 rounded skeleton" />
          </div>
        ))}
      </div>
    );
  }

  return (
    <section className="mb-10 md:mb-14">
      <div className="flex flex-col sm:flex-row sm:justify-between sm:items-end gap-3 mb-6 md:mb-8">
        <div>
          <h2 className="section-heading">Browse by Category</h2>
          <p className="section-description mt-1.5">Verified local services in Sangli, Maharashtra</p>
        </div>
        <button 
          onClick={() => router.push('/categories')}
          className="group flex items-center gap-1.5 text-primary text-sm font-semibold hover:gap-2 transition-all btn-ui"
        >
          View All Categories <span className="text-base">→</span>
        </button>
      </div>

      <motion.div 
        variants={containerVariants}
        initial="hidden"
        whileInView="show"
        viewport={{ once: true }}
        className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 xl:grid-cols-7 gap-4 md:gap-5"
      >
        {categories.map((cat) => (
          <motion.div
            key={cat.id}
            variants={itemVariants}
            whileHover={{ y: -8 }}
            onClick={() => router.push(`/categories?id=${cat.id}`)}
            className="flex flex-col items-center group cursor-pointer h-full"
          >
            <div 
              className="w-20 h-20 md:w-22 md:h-22 rounded-full bg-white border border-slate-100 shadow-subtle group-hover:shadow-premium flex items-center justify-center transition-all duration-500 overflow-hidden relative"
            >
              {/* Subtle gradient bg overlay on hover */}
              <div 
                className="absolute inset-0 opacity-0 group-hover:opacity-5 transition-opacity duration-500"
                style={{ backgroundColor: cat.color || 'var(--primary)' }}
              />
              <div className="group-hover:scale-110 group-hover:rotate-6 transition-transform duration-500 relative z-10 flex items-center justify-center">
                {renderDynamicIcon(cat.icon, 30, cat.color || 'var(--primary)')}
              </div>
            </div>
            <span className="mt-3.5 text-xs md:text-sm font-black text-slate-500 group-hover:text-primary transition-colors text-center px-1 tracking-tight leading-tight">
              {cat.name}
            </span>
          </motion.div>
        ))}
      </motion.div>

      <div className="mt-8 md:mt-10">
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-sm md:text-base font-bold text-slate-900">Popular Businesses</h3>
          <button
            onClick={() => router.push('/search')}
            className="text-xs md:text-sm text-primary font-semibold"
          >
            View All
          </button>
        </div>

        <div className="flex gap-3 md:gap-4 overflow-x-auto pb-2 no-scrollbar snap-x snap-mandatory">
          {topBusinesses.map((biz, idx) => {
            const imageSrc = (biz.image_url && biz.image_url.length > 10)
              ? biz.image_url
              : (biz.image && biz.image.length > 10)
                ? biz.image
                : `https://images.unsplash.com/photo-1581578731548-c64695cc6952?q=80&w=400&sig=${idx}`;

            return (
              <button
                key={biz.id || idx}
                onClick={() => router.push(`/business/${biz.id}`)}
                className="snap-start shrink-0 basis-[calc((100%-0.75rem)/2)] sm:basis-[calc((100%-1.5rem)/3)] lg:basis-[calc((100%-2.25rem)/4)] bg-white border border-slate-100 rounded-xl shadow-sm hover:shadow-md transition-all text-left overflow-hidden"
              >
                <img src={imageSrc} alt={biz.name} className="w-full h-24 md:h-28 object-cover" />
                <div className="p-3">
                  <p className="text-[10px] uppercase tracking-[0.14em] text-slate-400 font-bold">
                    {biz.category_name || 'Service'}
                  </p>
                  <h4 className="text-sm font-bold text-slate-900 mt-1 line-clamp-1">
                    {biz.name || 'Business Partner'}
                  </h4>
                  <p className="text-xs text-slate-500 mt-1 line-clamp-1">
                    {biz.address || 'Sangli, Maharashtra'}
                  </p>
                </div>
              </button>
            );
          })}
        </div>
      </div>
    </section>
  );
}

